set-variable.value:
#[vars.dashboardData ++ [{
                                      bgName:       vars.currentBgName,
                                      bgId:         vars.currentBgId,
                                      environments: vars.bgEnvData
                                  }]]

ee:variables.ee:set-variable:
%dw 2.0
output text/plain
fun barClass(v: Number, warnAt: Number, critAt: Number) =
    if (v >= critAt) "bar-crit"
    else if (v >= warnAt) "bar-warn"
    else "bar-ok"
fun pctBar(v: Number, warnAt: Number, critAt: Number) =
    '<div class="metric-cell"><div class="bar-wrap"><div class="bar-fill '
    ++ barClass(v, warnAt, critAt)
    ++ '" style="width:' ++ (v as String) ++ '%"></div></div><span>' ++ (v as String) ++ '%</span></div>'
fun renderGateway(gw) =
    do {
        var cpuPct = gw.cpu  as Number default 0
        var memPct = gw.mem  as Number default 0
        var statusBadge = if (gw.status == "STARTED")
                            '<span class="badge badge-started">STARTED</span>'
                          else
                            '<span class="badge badge-stopped">' ++ gw.status ++ '</span>'
        ---
        '<tr>
          <td><strong>' ++ gw.name ++ '</strong></td>
          <td>' ++ statusBadge ++ '</td>
          <td>' ++ pctBar(cpuPct, 60, 80) ++ '</td>
          <td>' ++ pctBar(memPct, 50, 70) ++ '</td>
          <td>' ++ (gw.errors as String) ++ '</td>
        </tr>'
    }
fun renderEnv(env) =
    '<div class="env-section">
      <div class="env-label">Environment: ' ++ env.envName ++ '</div>'
    ++ (if (sizeOf(env.gateways) == 0)
          '<div class="no-gw">No managed gateways found.</div>'
        else
          '<table>
            <thead><tr>
              <th>Gateway Name</th>
              <th>Status</th>
              <th>CPU (5 min avg)</th>
              <th>Memory (5 min avg)</th>
              <th>Errors (5 min)</th>
            </tr></thead>
            <tbody>'
          ++ ((env.gateways map renderGateway($)) joinBy "")
          ++ '</tbody></table>')
    ++ '</div>'
fun renderBg(bg) =
    '<div class="bg-card">
      <div class="bg-header"><span class="bg-icon">&#9635;</span> Business Group: ' ++ bg.bgName ++ '</div>'
    ++ ((bg.environments map renderEnv($)) joinBy "")
    ++ '</div>'
---
'<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1.0" />
<title>Global Omni Gateway Status</title>
<style>
  :root {
    --omni-blue:   #00a1e0;
    --omni-dark:   #032d60;
    --omni-mid:    #1b4f9b;
    --omni-light:  #e8f4fd;
    --omni-white:  #ffffff;
    --omni-green:  #2ecc71;
    --omni-red:    #e74c3c;
    --omni-gray:   #f4f6f9;
    --omni-border: #d0dce8;
    --radius: 8px;
    font-family: "Salesforce Sans", Arial, sans-serif;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { background: var(--omni-gray); color: #1a1a1a; }

  header {
    background: linear-gradient(135deg, var(--omni-dark) 0%, var(--omni-mid) 100%);
    color: var(--omni-white);
    padding: 24px 40px;
    display: flex; align-items: center; gap: 16px;
    box-shadow: 0 2px 8px rgba(0,0,0,.25);
  }
  .logo { font-size: 28px; font-weight: 700; letter-spacing: -0.5px; }
  .logo span { color: var(--omni-blue); }
  .subtitle { font-size: 13px; opacity: .75; margin-top: 2px; }

  .refresh-bar {
    background: var(--omni-light);
    border-bottom: 1px solid var(--omni-border);
    padding: 8px 40px;
    font-size: 12px; color: #555;
    display: flex; justify-content: space-between; align-items: center;
  }
  .refresh-btn {
    background: var(--omni-blue); color: #fff; border: none;
    padding: 5px 14px; border-radius: 4px; cursor: pointer; font-size: 12px;
  }
  .refresh-btn:hover { background: var(--omni-mid); }

  main { padding: 32px 40px; }

  .bg-card {
    background: var(--omni-white);
    border: 1px solid var(--omni-border);
    border-radius: var(--radius);
    margin-bottom: 28px;
    overflow: hidden;
    box-shadow: 0 1px 4px rgba(0,0,0,.07);
  }
  .bg-header {
    background: linear-gradient(90deg, var(--omni-dark) 0%, var(--omni-mid) 100%);
    color: var(--omni-white);
    padding: 14px 20px;
    font-size: 16px; font-weight: 600;
    display: flex; align-items: center; gap: 8px;
  }
  .bg-icon { font-size: 20px; }

  .env-section { padding: 16px 20px 0; }
  .env-label {
    font-size: 12px; font-weight: 700; letter-spacing: .08em;
    text-transform: uppercase; color: var(--omni-mid);
    padding: 0 0 8px; border-bottom: 1px solid var(--omni-border);
    margin-bottom: 10px;
  }

  table { width: 100%; border-collapse: collapse; margin-bottom: 16px; }
  th {
    background: var(--omni-light);
    color: var(--omni-mid);
    font-size: 11px; font-weight: 700; letter-spacing: .06em;
    text-transform: uppercase;
    padding: 8px 12px; text-align: left;
    border-bottom: 2px solid var(--omni-border);
  }
  td { padding: 10px 12px; font-size: 13px; border-bottom: 1px solid var(--omni-border); }
  tr:last-child td { border-bottom: none; }
  tr:hover td { background: var(--omni-light); }

  .badge {
    display: inline-block; padding: 3px 10px; border-radius: 12px;
    font-size: 11px; font-weight: 700; letter-spacing: .04em;
  }
  .badge-started { background: #d4edda; color: #155724; }
  .badge-stopped { background: #f8d7da; color: #721c24; }

  .metric-cell { display: flex; align-items: center; gap: 6px; }
  .bar-wrap { width: 60px; height: 6px; background: #dde3ec; border-radius: 3px; overflow: hidden; }
  .bar-fill { height: 100%; border-radius: 3px; }
  .bar-ok   { background: var(--omni-green); }
  .bar-warn { background: #f39c12; }
  .bar-crit { background: var(--omni-red); }

  .no-gw { color: #888; font-style: italic; font-size: 12px; padding: 10px 0 16px; }

  footer {
    text-align: center; padding: 20px;
    font-size: 11px; color: #999;
    border-top: 1px solid var(--omni-border);
  }
</style>
</head>
<body>
<header>
  <div>
    <div class="logo">&#9001; <span>Omni</span> Gateway Status</div>
    <div class="subtitle">Global Omni Gateway Status &mdash; live metrics (last 5 min)</div>
  </div>
</header>
<div class="refresh-bar">
  <span id="ts">Loading...</span>
  <button class="refresh-btn" onclick="location.reload()">&#8635; Refresh</button>
</div>
<main>'
++ ((vars.dashboardData map renderBg($)) joinBy "")
++ '</main>
<footer>MuleSoft Omni Gateway Monitor &mdash; Powered by Anypoint Platform</footer>
<script>document.getElementById("ts").textContent = "Last refreshed: " + new Date().toLocaleString();</script>
</body>
</html>'
